import{_ as t,o as a,c as r,ai as n}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"STEREO READER","text":"Train or relax your eyes while reading your favorite books","image":{"src":"/logo.svg","alt":"STEREO READER"},"actions":[{"theme":"brand","text":"Open the App","link":"/app/","target":"_blank"},{"theme":"alt","text":"Open a Book","link":"/app/#try","target":"_blank"},{"text":"Ask Questions","link":"https://t.me/stereoreader_chat","theme":"alt"}]},"features":[{"title":"Read your favorite books","details":"You can read text, PDF, <a href=\\"https://stereoreader.github.io/app/#try\\">EPUB</a>, FB2 files in stereo or mono mode","icon":{"src":"/feature-read.png","width":"100%"}},{"title":"Relax your eyes","details":"You can read books or view images with comfortable settings to relax your eyes with parallel view","icon":{"src":"/feature-relax.png","width":"100%"}},{"title":"Train your eyes","details":"You can train your vision to improve focus and clarity by reading with more challenging settings (smaller font size, wider gap between columns, longer distance)","icon":{"src":"/feature-train.png","width":"100%"}}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function i(s,e,l,c,h,d){return a(),r("div",null,[...e[0]||(e[0]=[n('<p>Disclaimer: I don&#39;t make make any medical claims; I only assume the existing possibility of improving vision with eye muscle exercises.</p><p>Being myopic (-4.5d), in 2023 I started doing simple eye exercises for 5–10 minutes before falling asleep. Since then, my vision improved to some degree, which I considered worth sharing, so I created a YouTube channel in Russian to share my experience. By that time, due to regular exercises, I had acquired pretty good eye muscle sensitivity, so I could feel which eye muscles contract and relax, given that I had learned <a href="https://en.wikipedia.org/wiki/Extraocular_muscles" target="_blank" rel="noreferrer">eye muscle anatomy</a> in detail. This allowed me to develop my own precise view of what causes myopia. This is a logical continuation of the <a href="https://en.wikipedia.org/wiki/Bates_method" target="_blank" rel="noreferrer">Bates method</a>. Regardless of the mainstream consensus that it is false, the main idea—that coarse focusing is done by extraocular muscles and final focusing by the eye lens—allowed many people who shared their experiences with me to get rid of myopia and other eye focusing problems. I even read a 2018 article in an ophthalmological journal claiming that the Bates theory is not entirely without merit and that further studies should be conducted on the matter (unfortunately, I cannot find it now).</p><p>My experience suggested that myopia happens due to shortening of the eye <a href="https://en.wikipedia.org/wiki/Extraocular_muscles" target="_blank" rel="noreferrer">rectus muscles</a>, especially the medial ones (internal, near the nose), which converge the eyes for near focusing. In July 2025, I began stereo reading—reading text in two columns in parallel view—where the eyes diverge to the point of exotropia, a state in which the eyes diverge beyond parallel alignment. I also found that my myopic audience has very poor ability to diverge and achieve any significant exotropia, whereas people without myopia have strong exotropia ability. Since then, exotropia and stereo reading have become my main tools for training my eyes. Reading alone is used in many vision improvement systems, including Bates’.</p><p>So I started in June 2025 being able to read (in non-stereo mode, just regular text) 2 mm lowercase letters from a 33-centimeter distance and ended on December 31 being able to read 7 mm lowercase letters from a 3-meter distance. That was a 2.6× improvement in angular letter size, which also corresponded to significant improvement in my everyday vision. Since then, I have been convinced that eye muscle exercises can be a working tool to mitigate eye focusing problems such as myopia.</p><p>In June 2025, I started the <a href="https://stereoreader.github.io/app/" target="_blank" rel="noreferrer">Stereo Reader web app</a> as my tool for stereo reading. Vue/TypeScript/PWA were selected for the implementation. What seemed like an easy project soon became a challenge.</p><p><img src="https://dev-to-uploads.s3.amazonaws.com/uploads/articles/mkrncwlj3t22iujnlhz0.jpg" alt="Home screen"></p><p><img src="https://dev-to-uploads.s3.amazonaws.com/uploads/articles/jsv1hzwflk1c44pnmu3b.jpg" alt="Reading mode"></p><p>After I shared the app with my eye training audience, it became clear that support for many e-book formats was required, including those with large amounts of text. Moreover, when adjusting reading settings such as font size, gap between text columns, and the span of the reading area, the currently visible text on the screen should not be lost.</p><p>So I developed a simple semantic system where any text document format is split into paragraphs (called “chunks” for brevity), each with its own font style, with lines calculated dynamically character by character based on the text column width. Since I had spent a lot of time <a href="https://stackoverflow.com/search?tab=votes&amp;q=user%3a14098260%20benchmark&amp;searchOn=3" target="_blank" rel="noreferrer">benchmarking</a> JavaScript and <a href="https://dev.to/alexander-nenashev/series/27389" target="_blank" rel="noreferrer">avoiding any extra string/array allocation</a>, I achieved fairly fast text layout calculation. However, it still takes 300–400 ms to process a huge novel like Asimov’s <em>Forward the Foundation</em> (about 140,000 words) on mid-range mobile devices (I tested on Snapdragon 720G). The issue is that layout recalculation occurs on any setting change that affects text column width. In any case, the UX is acceptable.</p><p>Having the text layout available, I implemented virtual scrolling while maintaining the full text container’s real height. This allows the text to appear as if it were loaded into a single DOM element with scrolling. Further improvements could include rethinking how users interact with partial scrolling and using Web Workers to process text in parallel.</p><p>Further work included adding stereo image viewing and introducing games, such as a moving ball to train exotropia in motion, and so on.</p><p>In any case, this project seems to have become my ongoing lifelong journey, and I welcome anyone to join.</p><p><a href="https://stereoreader.github.io" target="_blank" rel="noreferrer">The website</a> will include documentation on usage, the application can be tried <a href="https://stereoreader.github.io/app/#try" target="_blank" rel="noreferrer">here</a>. You can also join its <a href="https://www.youtube.com/channel/UCbRfdGzQ0Lwm87MthvMfcyw" target="_blank" rel="noreferrer">YouTube channel</a> and <a href="https://t.me/stereoreader" target="_blank" rel="noreferrer">Telegram channel</a> for future tutorials and news, and ask any questions in the <a href="https://t.me/stereoreader_chat" target="_blank" rel="noreferrer">community</a> or via <a href="https://t.me/alexoran" target="_blank" rel="noreferrer">telegram</a> or <a href="mailto:aleks4hour@gmail.com" target="_blank" rel="noreferrer">email</a>.</p>',13)])])}const u=t(o,[["render",i]]);export{p as __pageData,u as default};
